#include <string>
#include <unordered_set>

class Solution {
public:
    int appendCharacters(std::string s, std::string t) {
        std::unordered_set<char> t_set(t.begin(), t.end());
        int result = s.length();
        for (int i = s.length(); i > 0; --i) {
            if (!t_set.count(s[i])) {
                result = i;
                break;
            }
        }
        return result;
    }
};
